mapper.select:
SELECT * FROM rally_meetup


        AND creator_id = #{param.creatorId}


        AND biz_id IN (
            SELECT rally_meetup_id FROM rally_meetup_registration
            WHERE user_id = #{param.userId} AND status IN ('JOINED','REVIEWED')
        )



        AND status IN ('OPEN','FULL') AND end_time > NOW()



        AND (
            status IN ('FINISHED','CLOSED')
            OR (status IN ('OPEN','FULL') AND end_time < NOW())
        )



        AND biz_id < #{param.lastId}


ORDER BY biz_id DESC
LIMIT #{param.limit}

SELECT * FROM ( (SELECT m.* FROM rally_meetup m WHERE m.creator_id = #{userId} AND m.status IN ('OPEN','FULL') AND m.end_time > NOW() AND EXISTS ( SELECT 1 FROM rally_meetup_registration r WHERE r.rally_meetup_id = m.biz_id AND r.status = 'pending' )) UNION (SELECT m.* FROM rally_meetup m WHERE (m.status = 'FINISHED' OR (m.status IN ('OPEN','FULL') AND m.end_time < NOW())) AND m.end_time + INTERVAL #{deadlineDays} DAY > NOW() AND EXISTS ( SELECT 1 FROM rally_meetup_registration r WHERE r.rally_meetup_id = m.biz_id AND r.user_id = #{userId} AND r.status = 'JOINED' ) AND NOT EXISTS ( SELECT 1 FROM rally_meetup_score s WHERE s.rally_meetup_id = m.biz_id )) UNION (SELECT m.* FROM rally_meetup m WHERE EXISTS ( SELECT 1 FROM rally_meetup_chat_user cu WHERE cu.meetup_id = m.biz_id AND cu.user_id = #{userId} AND cu.unread_count > 0 )) ) t
AND t.biz_id < #{lastId}
ORDER BY t.biz_id DESC LIMIT #{limit}

SELECT * FROM rally_meetup m
WHERE (m.creator_id = #{userId}
   OR EXISTS (
       SELECT 1 FROM rally_meetup_registration r
       WHERE r.rally_meetup_id = m.biz_id AND r.user_id = #{userId} AND r.status IN ('JOINED','REVIEWED')
   ))

    AND m.biz_id < #{lastId}

ORDER BY m.biz_id DESC
LIMIT #{limit}
